const norm = (s: string) => s.toLowerCase().replace(/[^a-z0-9%\s؀-ۿ]/g, ' ').replace(/\s+/g, ' ').trim();

// Synonym canonicalisation: local vocabulary, romanised Urdu and common
// shorthand all fold onto the KB's canonical tokens before matching. Combined
// with typo tolerance below, each keyword effectively matches thousands of
// surface phrasings.
const SYNONYMS: Record<string, string> = {
  kameti: 'committee', kamety: 'committee', kamaiti: 'committee', beesi: 'committee', bisi: 'committee', bc: 'committee', circle: 'committee', circles: 'committee', committe: 'committee', comittee: 'committee', commitee: 'committee',
  paisa: 'money', paise: 'money', paisey: 'money', raqam: 'money', cash: 'money',
  munafa: 'profit', nafa: 'profit', faida: 'profit', earnings: 'profit', return: 'profit', returns: 'profit',
  sood: 'interest', riba: 'interest',
  sona: 'gold', tola: 'gold',
  qist: 'installment', instalment: 'installment', installments: 'installment', kist: 'installment',
  amanat: 'deposit', zamanat: 'deposit', deposits: 'deposit',
  inam: 'bonus', prize: 'bonus',
  madad: 'help', halp: 'help',
  akaunt: 'account', acount: 'account',
  paswrd: 'password', pasword: 'password',
  wallat: 'vault', walat: 'vault', tijori: 'vault',
  mahana: 'monthly', rozana: 'daily',
  shariah: 'halal', shariat: 'halal', islamic: 'halal', islami: 'halal',
  jurmana: 'penalty', fine: 'penalty', penalties: 'penalty',
  turn: 'turn', bari: 'turn', qura: 'draw', qurandazi: 'draw',
};

// Bounded Levenshtein distance with early exit — the autocorrect. "helo"
// matches "hello", "comitee" matches "committee".
function lev(a: string, b: string, max: number): number {
  if (Math.abs(a.length - b.length) > max) return max + 1;
  let prev = Array.from({ length: b.length + 1 }, (_, i) => i);
  for (let i = 1; i <= a.length; i++) {
    const cur = [i];
    let rowMin = i;
    for (let j = 1; j <= b.length; j++) {
      cur[j] = Math.min(prev[j] + 1, cur[j - 1] + 1, prev[j - 1] + (a[i - 1] === b[j - 1] ? 0 : 1));
      if (cur[j] < rowMin) rowMin = cur[j];
    }
    if (rowMin > max) return max + 1;
    prev = cur;
  }
  return prev[b.length];
}

const canon = (t: string) => SYNONYMS[t] ?? t;
const tokensOf = (s: string) => norm(s).split(' ').filter(Boolean).map(canon);

// A query token matches a keyword token exactly, by synonym, or within a
// length-scaled typo budget (1 edit for 4–6 letters, 2 for 7+).
function tokenMatches(qt: string, kt: string): boolean {
  if (qt === kt) return true;
  if (kt.length < 4 || qt.length < 3) return false;
  const budget = kt.length >= 7 ? 2 : 1;
  return lev(qt, kt, budget) <= budget;
}

// Conversation context: Rafa remembers the topic area of the last answer, so a
// short follow-up ("what about the fee?", "and gold?", "why?") biases toward
// the same territory instead of resetting to a cold match.
let lastCat: string | null = null;
let lastId: string | null = null;
const FOLLOWUP = /\b(it|that|this|those|why|how|more|also|and|what about|kya|aur)\b/;

export function matchRafa(query: string): { entry: RafaEntry; score: number } | null {
  const qTokens = tokensOf(query);
  if (qTokens.join('').length < 2) return null;
  const isFollowup = qTokens.length <= 4 || FOLLOWUP.test(' ' + norm(query) + ' ');
  let best: RafaEntry | null = null;
  let bestScore = 0;
  for (const entry of RAFA_KB) {
    // Simple mode hides the investment layer, so Rafa must not answer with it.
    if (SIMPLE_MODE && (entry.cat === 'Vault & savings' || entry.cat === 'Profit & bonus')) continue;
    let score = 0;
    for (const kw of entry.k) {
      const kTokens = tokensOf(kw);
      if (!kTokens.length) continue;
      // a keyword matches when every one of its tokens is present (fuzzily) in the query
      const hit = kTokens.every(kt => qTokens.some(qt => tokenMatches(qt, kt)));
      if (hit) score += kTokens.length + (kTokens.length > 1 ? 1 : 0);
    }
    if (score > 0 && isFollowup && entry.cat === lastCat && entry.id !== lastId) score += 2; // context bias
    if (score > bestScore) { bestScore = score; best = entry; }
  }
  if (best && bestScore > 0) { lastCat = best.cat; lastId = best.id; return { entry: best, score: bestScore }; }
  return null;
}

